class AppLoggingTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        when (priority) {
            Log.VERBOSE -> Log.v(tag, message, t)
            Log.DEBUG -> Log.d(tag, message, t)
            Log.INFO -> Log.i(tag, message, t)
            Log.WARN -> Log.w(tag, message, t)
            Log.ERROR -> Log.e(tag, message, t)
            else -> Log.println(priority, tag, message)
        }
    }
}

fun initializeLogging() {
    if (BuildConfig.DEBUG) {
        Timber.plant(Timber.DebugTree())
        Timber.plant(AppLoggingTree())
    } else {
        Timber.plant(Timber.Tree())
        Timber.plant(AppLoggingTree())
    }
}

val HttpLoggingInterceptor.Level.Companion.VERBOSE: HttpLoggingInterceptor.Level
    get() = HttpLoggingInterceptor.Level.BODY